glsl.vertex:
varying vec2 vUv;
void main(){
 vUv=uv;
 gl_Position=projectionMatrix*modelViewMatrix*vec4(position,1.0);
}

glsl.fragment:
precision mediump float;
varying vec2 vUv;
uniform float uTime;
float hash(vec2 p){return fract(sin(dot(p,vec2(127.1,311.7)))*43758.5453123);}
float noise(vec2 p){vec2 i=floor(p);vec2 f=fract(p);vec2 u=f*f*(3.0-2.0*f);return mix(mix(hash(i),hash(i+vec2(1.0,0.0)),u.x),mix(hash(i+vec2(0.0,1.0)),hash(i+vec2(1.0,1.0)),u.x),u.y);}
void main(){
 vec2 p=vUv*2.0-1.0;
 float n=noise(vUv*8.0)+0.5*noise(vUv*19.0);
 float wash=sin((p.x*1.4+p.y*0.9+n*0.9)*3.14159)*0.5+0.5;
 vec3 paper=vec3(0.84,0.83,0.76);
 vec3 cyan=vec3(0.22,0.62,0.72);
 vec3 blue=vec3(0.13,0.32,0.50);
 vec3 violet=vec3(0.42,0.34,0.64);
 vec3 col=mix(paper,cyan,0.22+0.18*wash);
 col=mix(col,blue,smoothstep(-0.4,0.9,p.x+p.y*0.25)*0.22);
 col=mix(col,violet,smoothstep(0.1,1.0,-p.x+p.y*0.55)*0.20);
 col+=vec3((n-0.75)*0.055);
 float edge=smoothstep(0.72,1.35,length(p));
 col=mix(col,col*0.88,edge*0.28);
 gl_FragColor=vec4(col,0.92);
}
